mapper.update:
update edu_student_profile
student_name = #{studentName}, parent_user_id = #{parentUserId}, parent_name = #{parentName}, grade_name = #{gradeName}, class_name = #{className}, gender = #{gender}, interest_tags = #{interestTags}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
where profile_id = #{profileId}

mapper.select:
select count(1) from edu_student_profile p
left join sys_user su on su.user_id = p.student_user_id
left join sys_user pu on pu.user_id = p.parent_user_id

    p.status = '0'

        and p.student_user_id = #{studentUserId}


        and p.parent_user_id = #{parentUserId}


        and (
            su.school_id = #{params.schoolId}
            or pu.school_id = #{params.schoolId}
        )
